import json
import datetime

base = r'C:\Users\82789\.nanobot\workspace\self-improving'
files = []

for root, dirs, filenames in os.walk(base):
    # Skip hidden files
    filenames = [f for f in filenames if not f.startswith('.')]
    for f in filenames:
        path = os.path.join(root, f)
        try:
            stat = os.stat(path)
            files.append({
                'path': path.replace(base, '').lstrip('\\/'),
                'mtime': stat.st_mtime,
                'iso': datetime.datetime.fromtimestamp(stat.st_mtime).isoformat()
            })
        except Exception as e:
            print(f"Error reading {path}: {e}")

files.sort(key=lambda x: x['mtime'], reverse=True)
print(json.dumps(files[:20], indent=2, ensure_ascii=False))
