{"path": "C:\Users\82789\.nanobot\workspace\scan_self_improving.py", "content": "import os
import json
import datetime

base = r'C:\Users\82789\.nanobot\workspace\self-improving'
state_file = os.path.join(base, 'heartbeat-state.md')

# Read last_reviewed_change_at from state file
last_reviewed = None
if os.path.exists(state_file):
    with open(state_file, 'r', encoding='utf-8') as f:
        content = f.read()
        for line in content.splitlines():
            if line.startswith('last_reviewed_change_at:'):
                timestamp_str = line.split(':', 1)[1].strip()
                try:
                    last_reviewed = datetime.datetime.fromisoformat(timestamp_str)
                except:
                    pass

if not last_reviewed:
    last_reviewed = datetime.datetime.min

print(f"Last reviewed: {last_reviewed.isoformat()}")
print(f"Scanning for changes after: {last_reviewed.isoformat()}")
print("-" * 60)

changes = []
for root, dirs, filenames in os.walk(base):
    # Skip hidden files and the state file itself
    filenames = [f for f in filenames if not f.startswith('.') and f != 'heartbeat-state.md']
    for f in filenames:
        path = os.path.join(root, f)
        try:
            stat = os.stat(path)
            mtime = datetime.datetime.fromtimestamp(stat.st_mtime)
            if mtime > last_reviewed:
                rel_path = path.replace(base, '').lstrip('\\/')
                changes.append({
                    'path': rel_path,
                    'mtime': mtime.isoformat()
                })
        except Exception as e:
            print(f"Error reading {path}: {e}")

changes.sort(key=lambda x: x['mtime'])
print(f"Found {len(changes)} changed files:")
for change in changes:
    print(f"  {change['mtime']} - {change['path']}")
"}

